44	/// `application/json; charset=utf-8`.
45	pub const CT_JSON: &str = "application/json; charset=utf-8";
46	/// `text/html; charset=utf-8`.
47	pub const CT_HTML: &str = "text/html; charset=utf-8";
48	/// `text/plain; charset=utf-8` (text bodies, `next`/`prev`, DOT, `robots`, `kill`).
49	pub const CT_TEXT: &str = "text/plain; charset=utf-8";
50	/// `application/octet-stream` (the `download` route).
51	pub const CT_OCTET: &str = "application/octet-stream";
52	
53	/// `Cache-Control` value on `303` redirects (and the favicon redirect).
54	pub const CACHE_CONTROL_NOCACHE: &str = "no-cache, must-revalidate";
55	/// `Expires` value paired with [`CACHE_CONTROL_NOCACHE`] (a fixed past instant).
56	pub const EXPIRES_PAST: &str = "Thu, 01 Jan 1970 05:05:05 GMT";
