58	/// HTTP request method (only the two the UI uses are modelled).
59	#[derive(Debug, PartialEq, Eq, Clone, Copy)]
60	pub enum HttpMethod {
61	    Get,
62	    Post,
63	}
64	
65	impl HttpMethod {
66	    fn as_str(self) -> &'static str {
67	        match self {
68	            HttpMethod::Get => "GET",
69	            HttpMethod::Post => "POST",
70	        }
71	    }
72	}
73	
74	/// An incoming request. `path` is the URL path with any `?query` split off into
75	/// `query` (decoded key/value pairs).
76	pub struct Request<'a> {
77	    pub method: HttpMethod,
78	    pub path: &'a str,
79	    /// Decoded query-string pairs (e.g. `("path", "solve(...)")` for `/kill`).
80	    pub query: &'a [(String, String)],
81	    /// Decoded POST form fields (e.g. `("lemma-text", "lemma foo: ŌĆ”")`, or
82	    /// `("uploadedTheory", <source>)` for an upload).
83	    pub form: &'a [(String, String)],
84	}
85	
86	impl<'a> Request<'a> {
87	    pub fn get(path: &'a str) -> Request<'a> {
88	        Request { method: HttpMethod::Get, path, query: &[], form: &[] }
89	    }
90	    pub fn get_query(path: &'a str, query: &'a [(String, String)]) -> Request<'a> {
91	        Request { method: HttpMethod::Get, path, query, form: &[] }
92	    }
93	    pub fn post(path: &'a str, form: &'a [(String, String)]) -> Request<'a> {
94	        Request { method: HttpMethod::Post, path, query: &[], form }
95	    }
96	    fn field(&self, key: &str) -> &str {
97	        Self::lookup(self.form, key)
98	    }
99	    fn query_param(&self, key: &str) -> Option<&str> {
100	        self.query.iter().find(|(k, _)| k == key).map(|(_, v)| v.as_str())
101	    }
102	    fn lookup<'b>(pairs: &'b [(String, String)], key: &str) -> &'b str {
103	        pairs.iter().find(|(k, _)| k == key).map(|(_, v)| v.as_str()).unwrap_or("")
104	    }
105	}
106	
107	/// An outgoing response. `location` is set for `3xx` redirects; `no_cache`
108	/// requests the `Cache-Control`/`Expires` pair Yesod attaches to redirects.
109	#[derive(Debug, PartialEq, Eq, Clone)]
110	pub struct Response {
111	    pub status: u16,
112	    pub content_type: &'static str,
113	    pub body: String,
114	    pub location: Option<String>,
115	    pub no_cache: bool,
116	}
117	
118	impl Response {
119	    fn base(status: u16, content_type: &'static str, body: String) -> Response {
120	        Response { status, content_type, body, location: None, no_cache: false }
121	    }
122	    fn json(body: String) -> Response {
123	        Response::base(200, CT_JSON, body)
124	    }
125	    fn html(body: String) -> Response {
126	        Response::base(200, CT_HTML, body)
127	    }
128	    fn text(body: String) -> Response {
129	        Response::base(200, CT_TEXT, body)
130	    }
131	    fn octet(body: String) -> Response {
132	        Response::base(200, CT_OCTET, body)
133	    }
134	    fn see_other(location: String) -> Response {
135	        Response { status: 303, content_type: CT_TEXT, body: String::new(), location: Some(location), no_cache: true }
136	    }
137	    fn not_found(echoed_path: &str) -> Response {
138	        Response::base(404, CT_HTML, errors::render_not_found(echoed_path))
139	    }
140	    fn invalid_args(messages: &[&str]) -> Response {
141	        Response::base(400, CT_HTML, errors::render_invalid_args(messages))
142	    }
143	    fn bad_method(method: HttpMethod) -> Response {
144	        Response::base(405, CT_HTML, errors::render_bad_method(method.as_str()))
145	    }
146	    /// The static-handler `404` for a missing file (plain text, distinct from the
147	    /// full-HTML `404` of the dynamic router).
148	    fn static_missing() -> Response {
149	        Response::base(404, CT_TEXT, assets::STATIC_NOT_FOUND.to_string())
150	    }
151	}
