191	/// The prover-supplied callbacks. The web layer treats every returned string as an
192	/// opaque fragment; the *decisions* around these calls (version allocation, route
193	/// dispatch, envelope shape, content types, redirects) live in [`Server`].
194	pub trait ProverOps {
195	    /// Opaque per-version theory handle held by the [`Server`].
196	    type Theory;
197	
198	    // ---- pretty-printers / fragment producers ----
199	    /// Shell metadata (theory name, Tamarin version string, source filename).
200	    fn meta(&self, thy: &Self::Theory) -> Meta;
201	    /// Index-page row data (load time, origin, modified flag) for `thy`.
202	    fn root_meta(&self, thy: &Self::Theory) -> RootMeta;
203	    /// The `source`/`message`/`download` body: the theory source, verbatim.
204	    fn source_text(&self, thy: &Self::Theory) -> String;
205	    /// Inner HTML of the west proof-script pane at `index`.
206	    fn west_pane(&self, thy: &Self::Theory, index: u64) -> String;
207	    /// Center-pane content (html + title) for a `main/*` view at `index`.
208	    fn main_content(&self, thy: &Self::Theory, index: u64, req: &MainReq) -> Content;
209	    /// Raw (unescaped) current source of a lemma, for the edit form.
210	    fn lemma_source(&self, thy: &Self::Theory, name: &str) -> Option<String>;
211	    /// Graphviz DOT for an `interactive-graph-def` node.
212	    fn graph_dot(&self, thy: &Self::Theory, tail: &[String]) -> String;
213	    /// The `next`/`prev` target URL (bare path), from the prover's traversal.
214	    fn nav_target(&self, thy: &Self::Theory, index: u64, dir: NavDir, mode: &str, lemma: &str) -> String;
215	    /// The `get_and_append` alert message (names the file appended to).
216	    fn append_message(&self, thy: &Self::Theory) -> String;
217	    /// Raw bytes of a `/static/<path>` asset, or `None` if the file is absent.
218	    fn static_file(&self, path: &[String]) -> Option<Vec<u8>>;
219	
220	    // ---- mutations / loads ----
221	    /// Parse an uploaded theory source into a theory, or `None` on failure.
222	    fn load_theory(&self, source: &str) -> Option<Self::Theory>;
223	    /// Re-read the theory from its source in place (the `reload` route).
224	    fn reload(&self, thy: &Self::Theory) -> Self::Theory;
225	    /// Apply proof method `n` at `(lemma, path)`. `Some((theory, focus))` on
226	    /// success (`focus` = the prover's next open goal, incl. root `_`); `None`
227	    /// if the method application failed (the web layer answers a JSON alert).
228	    fn apply_method(&self, thy: &Self::Theory, lemma: &str, n: usize, path: &[String]) -> Option<(Self::Theory, Vec<String>)>;
229	    /// Autoprove per `spec`. Returns the new theory and resulting focus path.
230	    fn autoprove(&self, thy: &Self::Theory, spec: &Autoprove) -> (Self::Theory, Vec<String>);
231	    /// Edit lemma `name` in place. `Some` = the modified theory; `None` = parse/wf
232	    /// failure or unknown lemma (the web layer then re-renders the edit form).
233	    fn edit_lemma(&self, thy: &Self::Theory, name: &str, text: &str) -> Option<Self::Theory>;
234	    /// Add a lemma at position `pos`. `Some`/`None` as for [`Self::edit_lemma`].
235	    fn add_lemma(&self, thy: &Self::Theory, pos: &str, text: &str) -> Option<Self::Theory>;
236	    /// Delete lemma `name` in place. `Some` = the modified theory (redirect to the
237	    /// help view); `None` = lemma not found (redirect to the delete view).
238	    fn delete_lemma(&self, thy: &Self::Theory, name: &str) -> Option<Self::Theory>;
239	
240	    // ---- del/path + verify (theory-path operations) ----
241	    /// Whether `lemma` is a lemma present in `thy`. Drives the `verify/proof/ŌĆ”`
242	    /// redirect-vs-content choice: a `verify/proof/{lemma}[/path]` redirects to the
243	    /// proof view iff the lemma is present, otherwise the help pane is returned.
244	    fn lemma_present(&self, thy: &Self::Theory, lemma: &str) -> bool;
245	    /// Delete the proof at the lemma node `name` (`del/path/lemma/{name}`),
246	    /// producing a fresh theory version. `None` if the lemma cannot be removed
247	    /// (absent) ŌĆö the web layer then answers a "removing the selected lemma failed"
248	    /// alert.
249	    fn del_lemma_path(&self, thy: &Self::Theory, name: &str) -> Option<Self::Theory>;
250	    /// Remove the proof step at a proof node (`del/path/proof/ŌĆ”`, or the diff
251	    /// `del/path/diffProof/ŌĆ”` when `diff`), producing a fresh theory version.
252	    /// `None` if the node cannot be removed (nonexistent lemma or unremovable node)
253	    /// ŌĆö the web layer then answers a "removing the selected proof step failed"
254	    /// alert.
255	    fn del_proof_step(&self, thy: &Self::Theory, lemma: &str, path: &[String], diff: bool) -> Option<Self::Theory>;
256	
257	    // ---- diff-mode (observational equivalence) ----
258	    /// Apply a diff proof method; `Some`/`None` as for [`Self::apply_method`].
259	    fn apply_diff_method(&self, thy: &Self::Theory, lemma: &str, n: usize, path: &[String]) -> Option<(Self::Theory, Vec<String>)>;
260	    /// Autoprove a single diff lemma per `spec`; returns theory + focus path.
261	    fn autoprove_diff(&self, thy: &Self::Theory, spec: &AutoproveDiff) -> (Self::Theory, Vec<String>);
262	    /// Autoprove all lemmas per `spec`; returns the resulting theory.
263	    fn autoprove_all(&self, thy: &Self::Theory, spec: &AutoproveAll) -> Self::Theory;
264	}
