710	/// Build a `del/path/lemma/{name}` redirect target: the `overview/lemma/{name}`
711	/// URL at version `index`.
712	fn overview_lemma_path(kind: ShellKind, index: u64, name: &str) -> String {
713	    format!("/thy/{}/{}/overview/lemma/{}", kind.path(), index, name)
714	}
