1	//! The full-page theory-view HTML shell (`overview/*`) and the index page (`/`).
2	//!
3	//! Observed structure (constant across theories after substituting the
4	//! parameters below): a fixed `<head>` of stylesheet/script links, a north header
5	//! bar, then four layout panes ŌĆö west "Proof scripts", east "Debug information"
6	//! (always empty), and center "Visualization display". The west pane embeds the
7	//! proof-script markup (see [`super::proofscript`]); the center pane embeds the
8	//! currently-selected main content HTML.
9	//!
10	//! The shell is shared between the ordinary trace view and the observational-
11	//! equivalence (diff) view: the only differences are the `<title>` prefix
12	//! (`Theory:` vs `DiffTheory:`), the `/thy/<kind>/` segment in every internal
13	//! link (`trace` vs `equiv`), and the presence of the Actions-menu "Append
14	//! modified lemmas" item (trace only). These are captured by [`ShellKind`].
15	//!
16	//! Scaffolding constants in `shell_template` are byte-exact copies of oracle
17	//! output. The body has no trailing newline (ends `</html>`).
18	
19	use super::escape::html_escape;
20	use super::shell_template::{
21	    APPEND_ITEM, PAGE_MID, PAGE_PREFIX, PAGE_TAIL, ROOT_TEMPLATE,
22	};
23	
24	/// Parameters that vary between rendered theory-view pages.
25	pub struct PageParams<'a> {
26	    /// Theory name, shown in `<title>ŌĆ”Theory: NAME</title>`.
27	    pub theory_name: &'a str,
28	    /// Resolved numeric theory index used in every internal URL.
29	    pub index: u64,
30	    /// Tamarin version string shown in the header (e.g. `"1.13.0"`).
31	    pub version: &'a str,
32	    /// Source filename used in the download / append links (e.g. `"foo.spthy"`).
33	    pub filename: &'a str,
34	}
35	
36	/// Which theory-view shell variant to render.
37	#[derive(Debug, PartialEq, Eq, Clone, Copy)]
38	pub enum ShellKind {
39	    /// Ordinary trace analysis: `/thy/trace/`, `Theory:` title, append item present.
40	    Trace,
41	    /// Observational-equivalence (diff) analysis: `/thy/equiv/`, `DiffTheory:`
42	    /// title, no append item.
43	    Equiv,
44	}
45	
46	impl ShellKind {
47	    /// The `/thy/<kind>/` path segment.
48	    pub fn path(self) -> &'static str {
49	        match self {
50	            ShellKind::Trace => "trace",
51	            ShellKind::Equiv => "equiv",
52	        }
53	    }
54	    fn title_diff(self) -> &'static str {
55	        match self {
56	            ShellKind::Trace => "",
57	            ShellKind::Equiv => "Diff",
58	        }
59	    }
60	    fn append(self) -> &'static str {
61	        match self {
62	            ShellKind::Trace => APPEND_ITEM,
63	            ShellKind::Equiv => "",
64	        }
65	    }
66	}
