68	/// Render the trace theory-view page (the common case).
69	pub fn render_page(p: &PageParams, west_inner: &str, center_inner: &str) -> String {
70	    render_page_kind(ShellKind::Trace, p, west_inner, center_inner)
71	}
72	
73	/// Render the theory-view page for a given shell variant.
74	pub fn render_page_kind(
75	    kind: ShellKind,
76	    p: &PageParams,
77	    west_inner: &str,
78	    center_inner: &str,
79	) -> String {
80	    let idx = p.index.to_string();
81	    // Fill the append slot first so its own KIND/IDX/FILENAME slots are then
82	    // resolved by the scalar substitutions below.
83	    let prefix = PAGE_PREFIX
84	        .replace("┬¦APPEND┬¦", kind.append())
85	        .replace("┬¦DIFF┬¦", kind.title_diff())
86	        .replace("┬¦NAME┬¦", &html_escape(p.theory_name))
87	        .replace("┬¦KIND┬¦", kind.path())
88	        .replace("┬¦IDX┬¦", &idx)
89	        .replace("┬¦VERSION┬¦", p.version)
90	        .replace("┬¦FILENAME┬¦", p.filename);
91	    let mut out = String::with_capacity(
92	        prefix.len() + west_inner.len() + PAGE_MID.len() + center_inner.len() + PAGE_TAIL.len(),
93	    );
94	    out.push_str(&prefix);
95	    out.push_str(west_inner);
96	    out.push_str(PAGE_MID);
97	    out.push_str(center_inner);
98	    out.push_str(PAGE_TAIL);
99	    out
100	}
