135	/// Render a single index-page theory row. The `Version` cell is a plain
136	/// `Original` or an (unclosed, as observed) `<em>Modified`.
137	pub fn render_root_row(r: &RootRow) -> String {
138	    let version_cell = if r.modified { "<em>Modified" } else { "Original" };
139	    format!(
140	        "<tr><td><a href=\"/thy/trace/{}/overview/help\">{}</a></td><td>{}</td><td>{}</td><td>{}</td></tr>",
141	        r.index,
142	        html_escape(r.name),
143	        r.time,
144	        version_cell,
145	        r.origin,
146	    )
147	}
